```

**Verhaltens-Test** (`packages/shared/src/__tests__/block-id.test.ts`):

```ts
describe("Block ID", () => {
  test("generateBlockId erzeugt 8-Zeichen-String", () => {
    const id = generateBlockId();
    expect(id).toHaveLength(8);
    expect(typeof id).toBe("string");
  });

  test("generateBlockId erzeugt einzigartige IDs", () => {
    const ids = new Set(Array.from({ length: 100 }, () => generateBlockId()));
    expect(ids.size).toBe(100);
  });

  test("Block ohne id wird beim Parsen mit generierter id versehen", () => {
    const result = paragraphBlockSchema.parse({ type: "paragraph", text: "hello" });
    expect(result.id).toBeDefined();
    expect(result.id).toHaveLength(8);
  });

  test("Block mit expliziter id behält diese", () => {
    const result = paragraphBlockSchema.parse({
      type: "paragraph", text: "hello", id: "custom01"
    });
    expect(result.id).toBe("custom01");
  });

  test("Alle 6 Block-Typen erhalten id-Default", () => {
    const blocks = [
      { type: "paragraph", text: "t" },
      { type: "heading", level: 1, text: "t" },
      { type: "list", ordered: false, items: ["a"] },
      { type: "code", text: "t" },
      { type: "quote", text: "t" },
      { type: "table", headers: ["h"], rows: [["r"]] },
    ];
    for (const block of blocks) {
      const parsed = blockSchema.parse(block);
      expect(parsed.id).toBeDefined();
      expect(parsed.id).toHaveLength(8);
    }
  });

  test("blockSchema discriminatedUnion funktioniert weiterhin", () => {
    expect(() => blockSchema.parse({ type: "invalid" })).toThrow();
  });
});
```

